Here are the public test cases for feature1_type_name_rendering:
{
  "description": "Render a Terraform value type into its human-readable documentation name. Primitive types map to Boolean/Number/String, the dynamic pseudo-type maps to Dynamic, collection wrappers prepend 'List of '/'Set of '/'Map of ' to their recursively rendered element type, structural object types render as Object and tuple types render as Tuple. The type is provided in JSON wire format.",
  "cases": [
    {
      "input": {
        "op": "write_type",
        "type": "bool"
      },
      "expected_output": "Boolean"
    },
    {
      "input": {
        "op": "write_type",
        "type": "number"
      },
      "expected_output": "Number"
    },
    {
      "input": {
        "op": "write_type",
        "type": "string"
      },
      "expected_output": "String"
    },
    {
      "input": {
        "op": "write_type",
        "type": [
          "list",
          "bool"
        ]
      },
      "expected_output": "List of Boolean"
    },
    {
      "input": {
        "op": "write_type",
        "type": [
          "map",
          "bool"
        ]
      },
      "expected_output": "Map of Boolean"
    },
    {
      "input": {
        "op": "write_type",
        "type": [
          "object",
          {
            "bool": "bool"
          }
        ]
      },
      "expected_output": "Object"
    },
    {
      "input": {
        "op": "write_type",
        "type": [
          "list",
          [
            "map",
            [
              "set",
              [
                "object",
                {
                  "bool": "bool"
                }
              ]
            ]
          ]
        ]
      },
      "expected_output": "List of Map of Set of Object"
    }
  ]
}

Here are the public test cases for feature2_attribute_label:
{
  "description": "Render a single attribute's inline label. The label is wrapped in parentheses and begins with the rendered value type, followed by a behavior word derived from the attribute's flags (Required when required; Optional when optional, including optional+computed; Read-only when computed only), then optional Sensitive and Deprecated markers in that order, and finally the trimmed description text after the closing parenthesis. Surrounding whitespace in the description is trimmed.",
  "cases": [
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "required": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "(String, Required) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "required": true,
          "description": "This is an attribute.",
          "deprecated": true
        }
      },
      "expected_output": "(String, Required, Deprecated) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "required": true,
          "description": "This is an attribute.",
          "deprecated": true,
          "sensitive": true
        }
      },
      "expected_output": "(String, Required, Sensitive, Deprecated) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "optional": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "(String, Optional) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "optional": true,
          "computed": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "(String, Optional) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "computed": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "(String, Read-only) This is an attribute."
    },
    {
      "input": {
        "op": "attribute_description",
        "attribute": {
          "type": "string",
          "required": true,
          "description": " This is an attribute."
        }
      },
      "expected_output": "(String, Required) This is an attribute."
    }
  ]
}

Here are the public test cases for feature3_nested_attribute_label:
{
  "description": "Render the inline label for an attribute whose type is a nested object collection. The label opens with 'Attributes' plus a collection word (none for single, List/Set/Map otherwise). For single nesting the behavior word (Required/Optional/Read-only) is appended; for List/Set/Map nesting the minimum item count is appended as 'Min: N' when greater than zero. A maximum item count is appended as 'Max: N' when greater than zero, followed by the trimmed description.",
  "cases": [
    {
      "input": {
        "op": "nested_attribute_description",
        "attribute": {
          "description": "This is an attribute.",
          "optional": true,
          "nested_type": {
            "nesting_mode": "single",
            "attributes": {
              "foo": {
                "type": "string",
                "required": true,
                "description": "This is a nested attribute."
              }
            }
          }
        }
      },
      "expected_output": "(Attributes, Optional) This is an attribute."
    },
    {
      "input": {
        "op": "nested_attribute_description",
        "attribute": {
          "description": "This is an attribute.",
          "required": true,
          "nested_type": {
            "nesting_mode": "list",
            "min_items": 2,
            "max_items": 3,
            "attributes": {
              "foo": {
                "type": "string",
                "required": true,
                "description": "This is a nested attribute."
              }
            }
          }
        }
      },
      "expected_output": "(Attributes List, Min: 2, Max: 3) This is an attribute."
    },
    {
      "input": {
        "op": "nested_attribute_description",
        "attribute": {
          "description": "This is an attribute.",
          "nested_type": {
            "nesting_mode": "map",
            "attributes": {
              "foo": {
                "type": "string",
                "required": true,
                "description": "This is a nested attribute."
              }
            }
          }
        }
      },
      "expected_output": "(Attributes Map) This is an attribute."
    },
    {
      "input": {
        "op": "nested_attribute_description",
        "attribute": {
          "description": "This is an attribute.",
          "nested_type": {
            "nesting_mode": "set",
            "min_items": 5,
            "attributes": {
              "foo": {
                "type": "string",
                "required": true,
                "description": "This is a nested attribute."
              }
            }
          }
        }
      },
      "expected_output": "(Attributes Set, Min: 5) This is an attribute."
    }
  ]
}

