Here are the public test cases for feature5_schema_markdown:
{
  "description": "Render a complete provider/resource schema into a Markdown '## Schema' section. Attributes and blocks are partitioned into '### Required', '### Optional' and '### Read-Only' groups, each item rendered as a bullet with its inline type/behavior label, and nested object/block structures are emitted as linked sub-sections below. Input is a full schema document in JSON wire format; output is the rendered Markdown with trailing newlines trimmed.",
  "cases": [
    {
      "input": {
        "op": "render_schema",
        "schema": {
          "block": {
            "attributes": {
              "gateway_id": {
                "description_kind": "plain",
                "optional": true,
                "type": "string"
              },
              "id": {
                "computed": true,
                "description_kind": "plain",
                "optional": true,
                "type": "string"
              },
              "route_table_id": {
                "description_kind": "plain",
                "required": true,
                "type": "string"
              },
              "subnet_id": {
                "description_kind": "plain",
                "optional": true,
                "type": "string"
              }
            },
            "description_kind": "plain"
          },
          "version": 0
        }
      },
      "expected_output": "## Schema\n\n### Required\n\n- `route_table_id` (String)\n\n### Optional\n\n- `gateway_id` (String)\n- `subnet_id` (String)\n\n### Read-Only\n\n- `id` (String) The ID of this resource."
    }
  ]
}

Here are the public test cases for feature6_1_classify_attribute:
{
  "description": "Classify a single attribute into the documentation grouping role used to bucket it under Required/Optional/Read-Only headings. A required attribute yields role=required, an optional attribute (including optional+computed) yields role=optional, and a computed-only attribute yields role=read_only.",
  "cases": [
    {
      "input": {
        "op": "classify_attribute",
        "attribute": {
          "type": "string",
          "required": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "role=required\n"
    },
    {
      "input": {
        "op": "classify_attribute",
        "attribute": {
          "type": "string",
          "optional": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "role=optional\n"
    },
    {
      "input": {
        "op": "classify_attribute",
        "attribute": {
          "type": "string",
          "computed": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "role=read_only\n"
    },
    {
      "input": {
        "op": "classify_attribute",
        "attribute": {
          "type": "string",
          "optional": true,
          "computed": true,
          "description": "This is an attribute."
        }
      },
      "expected_output": "role=optional\n"
    }
  ]
}

Here are the public test cases for feature6_2_classify_block:
{
  "description": "Classify a single nested block into the documentation grouping role. A block with a minimum item count above zero yields role=required; a zero-minimum block that is empty or contains any required/optional descendant yields role=optional; a block whose every leaf is computed-only yields role=read_only.",
  "cases": [
    {
      "input": {
        "op": "classify_block",
        "block": {
          "nesting_mode": "single",
          "min_items": 1,
          "block": {
            "description": "b",
            "attributes": {
              "foo": {
                "type": "string",
                "required": true,
                "description": "a"
              }
            }
          }
        }
      },
      "expected_output": "role=required\n"
    },
    {
      "input": {
        "op": "classify_block",
        "block": {
          "nesting_mode": "single",
          "block": {
            "description": "b",
            "attributes": {
              "foo": {
                "type": "string",
                "optional": true,
                "description": "a"
              }
            }
          }
        }
      },
      "expected_output": "role=optional\n"
    },
    {
      "input": {
        "op": "classify_block",
        "block": {
          "nesting_mode": "single",
          "block": {
            "description": "b",
            "attributes": {
              "foo": {
                "type": "string",
                "computed": true,
                "description": "a"
              }
            }
          }
        }
      },
      "expected_output": "role=read_only\n"
    },
    {
      "input": {
        "op": "classify_block",
        "block": {
          "nesting_mode": "single",
          "block": {
            "description": "empty"
          }
        }
      },
      "expected_output": "role=optional\n"
    },
    {
      "input": {
        "op": "classify_block",
        "block": {
          "nesting_mode": "single",
          "block": {
            "description": "b",
            "block_types": {
              "foo": {
                "min_items": 1,
                "block": {
                  "attributes": {
                    "foo": {
                      "type": "string",
                      "required": true,
                      "description": "a"
                    }
                  }
                }
              }
            }
          }
        }
      },
      "expected_output": "role=optional\n"
    }
  ]
}

Here are the public test cases for feature7_1_plain_markdown:
{
  "description": "Flatten Markdown source into plain text, stripping formatting markup (headings, emphasis, inline code, list markers) while preserving the readable textual content.",
  "cases": [
    {
      "input": {
        "op": "plain_markdown",
        "text": "my Odly cAsed striNg"
      },
      "expected_output": "my Odly cAsed striNg"
    },
    {
      "input": {
        "op": "plain_markdown",
        "text": "# Heading\n\nSome **bold** and `code` text."
      },
      "expected_output": "Heading\nSome bold and code text."
    }
  ]
}

Here are the public test cases for feature7_2_prefix_lines:
{
  "description": "Prepend a fixed prefix string to every line of a multi-line text block, including the first line, leaving line breaks otherwise intact.",
  "cases": [
    {
      "input": {
        "op": "prefix_lines",
        "prefix": "  ",
        "text": "This text used\nmultiple lines"
      },
      "expected_output": "  This text used\n  multiple lines"
    },
    {
      "input": {
        "op": "prefix_lines",
        "prefix": "> ",
        "text": "single line"
      },
      "expected_output": "> single line"
    }
  ]
}

Here are the public test cases for feature7_3_code_file:
{
  "description": "Read a source file from disk and wrap its trimmed contents in a fenced code block tagged with the given format/language. When the file cannot be read, a normalized file_not_found error is produced naming the requested file.",
  "cases": [
    {
      "input": {
        "op": "code_file",
        "format": "terraform",
        "file": "provider.tf"
      },
      "expected_output": "```terraform\nprovider \"scaffolding\" {\n  # example configuration here\n}\n```"
    },
    {
      "input": {
        "op": "code_file",
        "format": "terraform",
        "file": "missing.tf"
      },
      "expected_output": "error=file_not_found\nfile=missing.tf\n"
    }
  ]
}
